            // Assert
            result.Should().NotBeNull();
            result.Value.parametros.Should().HaveCount(1);
            var parameter = result.Value.parametros.First();
            parameter.ParameterName.Should().Be($"@{DBHonorariosDadosContratoDicInfo.DtCad}");
            parameter.Value.Should().BeOfType<DateTime>();
            var expectedDate = DateTime.Parse(testDate);
            ((DateTime)parameter.Value).Should().Be(expectedDate);
            result.Value.where.Should().Contain($"CONVERT(DATE,[{DBHonorariosDadosContratoDicInfo.PTabelaNome}].[{DBHonorariosDadosContratoDicInfo.DtCad}], 103) = CONVERT(DATE, @{DBHonorariosDadosContratoDicInfo.DtCad}, 103)");
        }

        [Fact]
        public void WFiltro_DtCad_WhenValidDateRange_ShouldAddBothParametersAndGenerateBetweenClause()
        {
            // Arrange
            var startDate = "01/06/2023";
            var endDate = "30/06/2023";
            var filtro = new FilterHonorariosDadosContrato
            {
                DtCad = startDate,
                DtCad_end = endDate,
                LogicalOperator = TSql.And
            };
            // Act
            var result = _serviceS.WFiltro(filtro);
            // Assert
            result.Should().NotBeNull();
            result.Value.parametros.Should().HaveCount(2);
            var startParameter = result.Value.parametros.FirstOrDefault(p => p.ParameterName == $"@{DBHonorariosDadosContratoDicInfo.DtCad}");
            var endParameter = result.Value.parametros.FirstOrDefault(p => p.ParameterName == $"@{DBHonorariosDadosContratoDicInfo.DtCad}_end");
            startParameter.Should().NotBeNull();
            endParameter.Should().NotBeNull();
            startParameter!.Value.Should().BeOfType<DateTime>();
            endParameter!.Value.Should().BeOfType<DateTime>();
            ((DateTime)startParameter.Value).Should().Be(DateTime.Parse(startDate));
            ((DateTime)endParameter.Value).Should().Be(DateTime.Parse(endDate));
            result.Value.where.Should().Contain($"[{DBHonorariosDadosContratoDicInfo.PTabelaNome}].{DBHonorariosDadosContratoDicInfo.DtCad} BETWEEN @{DBHonorariosDadosContratoDicInfo.DtCad} AND @{DBHonorariosDadosContratoDicInfo.DtCad}_end");
        }

